package ru.memearena.meme.api; import ru.memearena.meme.domain.*; import java.time.Instant; import java.util.UUID; public record ModerationMemeItemResponse(UUID id,String title,String contentUrl,String sourceUrl,UUID uploaderId,String uploaderNickname,ModerationStatus moderationStatus,Instant createdAt){ public static ModerationMemeItemResponse of(Meme m,String nick){return new ModerationMemeItemResponse(m.getId(),m.getTitle(),m.getMediaAssetId()!=null?"/api/v1/media/"+m.getMediaAssetId()+"/content":m.getImageUrl(),m.getSourceUrl(),m.getUploaderId(),nick,m.getModerationStatus(),m.getCreatedAt());}}
